// --- Secure Log Sanitization Utilities ---

/**
 * Sanitize user-provided data before writing to logs to prevent log injection.
 * This removes/replaces characters that could be used for log forging:
 * - Newlines (\n, \r) which could create fake log entries
 * - Carriage returns
 * - ANSI escape sequences
 * - Null bytes
 * - Tab characters (optionally)
 */
function sanitizeForLog(input) {
    if (input === null || input === undefined) {
        return '';
    }

    const str = String(input);

    // Remove null bytes
    let sanitized = str.replace(/\0/g, '');

    // Replace newlines and carriage returns to prevent log injection/forging
    sanitized = sanitized.replace(/\r\n|\r|\n/g, ' [NEWLINE] ');

    // Remove ANSI escape sequences that could manipulate terminal output
    // eslint-disable-next-line no-control-regex
    sanitized = sanitized.replace(/\x1b\[[0-9;]*[a-zA-Z]/g, '');
    // eslint-disable-next-line no-control-regex
    sanitized = sanitized.replace(/[\x00-\x08\x0b\x0c\x0e-\x1f\x7f]/g, '');

    // Limit length to prevent log flooding
    const MAX_LOG_FIELD_LENGTH = 1024;
    if (sanitized.length > MAX_LOG_FIELD_LENGTH) {
        sanitized = sanitized.substring(0, MAX_LOG_FIELD_LENGTH) + '...[TRUNCATED]';
    }

    return sanitized;
}

/**
 * Sanitize an object's values recursively for safe logging
 */
function sanitizeObjectForLog(obj, depth = 0) {
    const MAX_DEPTH = 5;
    if (depth > MAX_DEPTH) {
        return '[MAX_DEPTH_EXCEEDED]';
    }

    if (obj === null || obj === undefined) {
        return obj;
    }

    if (typeof obj === 'string') {
        return sanitizeForLog(obj);
    }

    if (typeof obj === 'number' || typeof obj === 'boolean') {
        return obj;
    }

    if (Array.isArray(obj)) {
        return obj.slice(0, 100).map(item => sanitizeObjectForLog(item, depth + 1));
    }

    if (typeof obj === 'object') {
        const sanitized = {};
        const keys = Object.keys(obj).slice(0, 100); // Limit number of keys
        for (const key of keys) {
            const sanitizedKey = sanitizeForLog(key);
            sanitized[sanitizedKey] = sanitizeObjectForLog(obj[key], depth + 1);
        }
        return sanitized;
    }

    return sanitizeForLog(String(obj));
}

// --- Winston Logger Configuration ---

const auditLogger = winston.createLogger({
    level: 'info',
    format: winston.format.combine(
        winston.format.timestamp({
            format: 'YYYY-MM-DD HH:mm:ss.SSS'
        }),
        winston.format.errors({ stack: true }),
        // Custom format that ensures all interpolated values are sanitized
        winston.format.printf(({ timestamp, level, message, ...meta }) => {
            const sanitizedMessage = sanitizeForLog(message);
            const sanitizedMeta = Object.keys(meta).length > 0
                ? ' ' + JSON.stringify(sanitizeObjectForLog(meta))
                : '';
            return `${timestamp} [${level.toUpperCase()}] ${sanitizedMessage}${sanitizedMeta}`;
        })
    ),
    transports: [
        new winston.transports.File({
            filename: path.join(__dirname, 'logs', 'audit.log'),
            maxsize: 10 * 1024 * 1024, // 10MB
            maxFiles: 10,
            tailable: true
        }),
        new winston.transports.File({
            filename: path.join(__dirname, 'logs', 'error.log'),
            level: 'error',
            maxsize: 10 * 1024 * 1024,
            maxFiles: 5
        }),
        new winston.transports.Console({
            format: winston.format.combine(
                winston.format.colorize(),
                winston.format.timestamp({ format: 'YYYY-MM-DD HH:mm:ss.SSS' }),
                winston.format.printf(({ timestamp, level, message, ...meta }) => {
                    const sanitizedMessage = sanitizeForLog(message);
                    const sanitizedMeta = Object.keys(meta).length > 0
                        ? ' ' + JSON.stringify(sanitizeObjectForLog(meta))
                        : '';
                    return `${timestamp} ${level}: ${sanitizedMessage}${sanitizedMeta}`;
                })
            )
        })
    ]
});

// --- Safe Audit Log Function ---

/**
 * Write an audit log entry with all user-provided data sanitized
 */
function auditLog(action, details) {
    const sanitizedAction = sanitizeForLog(action);
    const sanitizedDetails = sanitizeObjectForLog(details);

    auditLogger.info(sanitizedAction, {
        audit: true,
        ...sanitizedDetails
    });
}

